function detectCollapse(el1, el2) {
  const s1 = getComputedStyle(el1);
  const s2 = getComputedStyle(el2);
  const expectedGap = parseFloat(s1.marginBottom) + parseFloat(s2.marginTop);
  const rect1 = el1.getBoundingClientRect();
  const rect2 = el2.getBoundingClientRect();
  const actualGap = rect2.top - rect1.bottom;
  return { expectedGap, actualGap, collapsed: actualGap < expectedGap };
}

function buildCardGridCSS() {
  return `
    * { box-sizing: border-box; }
    .grid {
      display: grid;
      grid-template-columns: repeat(3, 300px);
      gap: 16px;
    }
    .card { padding: 24px; border: 1px solid #e2e8f0; }
    @media (max-width: 768px) { .grid { grid-template-columns: repeat(2, 1fr); } }
    @media (max-width: 480px) { .grid { grid-template-columns: 1fr; } }
  `;
}

function getElementSizes(el) {
  const cs = getComputedStyle(el);
  return {
    contentWidth: parseFloat(cs.width),
    contentHeight: parseFloat(cs.height),
    paddingTop: parseFloat(cs.paddingTop),
    paddingBottom: parseFloat(cs.paddingBottom),
    borderTop: parseFloat(cs.borderTopWidth),
    marginTop: parseFloat(cs.marginTop),
    offsetWidth: el.offsetWidth,
    clientWidth: el.clientWidth,
    scrollWidth: el.scrollWidth
  };
}

