function buildElevationSystem() {
  const shadows = [
    '0 1px 2px rgba(0,0,0,0.05)',
    '0 4px 6px -1px rgba(0,0,0,0.1), 0 2px 4px -2px rgba(0,0,0,0.1)',
    '0 10px 15px -3px rgba(0,0,0,0.1), 0 4px 6px -4px rgba(0,0,0,0.1)',
    '0 20px 25px -5px rgba(0,0,0,0.1), 0 8px 10px -6px rgba(0,0,0,0.1)',
    '0 25px 50px -12px rgba(0,0,0,0.25)'
  ];
  return shadows.map((s,i) => `.elevation-${i+1} { box-shadow: ${s}; }`).join('\n');
}

function spacingGuide(role) {
  const guides = {
    button: { internal: 'padding', external: 'margin', reason: 'Padding increases click target; margin separates buttons' },
    section: { internal: 'padding', external: 'margin', reason: 'Padding keeps content from edges; margin creates vertical rhythm' },
    card: { internal: 'padding', external: 'margin', reason: 'Padding adds breathing room inside; margin separates cards in a grid' },
    listItem: { internal: 'padding', external: 'marginBottom', reason: 'Padding improves readability; margin adds space between items' }
  };
  return guides[role] || { internal: 'padding', external: 'margin', reason: 'Default approach' };
}

function buildClearfixSolutions() {
  return `
    /* Problem: parent collapses */
    .parent { background: #e2e8f0; }
    .float-child { float: left; width: 100px; height: 100px; background: #3b82f6; margin: 8px; }

    /* Fix 1: Clearfix */
    .clearfix::after { content: ''; display: table; clear: both; }

    /* Fix 2: BFC with overflow */
    .bfc-overflow { overflow: hidden; }

    /* Fix 3: Modern flow-root */
    .flow-root { display: flow-root; }
  `;
}

function positioningCheatsheet() {
  return {
    static: 'Default. In normal flow. top/left/right/bottom have no effect.',
    relative: 'Stays in flow but can be offset. Creates positioning context for children.',
    absolute: 'Removed from flow. Positioned relative to nearest non-static ancestor.',
    fixed: 'Removed from flow. Positioned relative to viewport (or transform ancestor).',
