function findStackingContexts(root) {
  const results = [];
  function check(el) {
    const cs = getComputedStyle(el);
    const triggers = [];
    if (cs.position !== 'static' && cs.zIndex !== 'auto') triggers.push('position+z-index');
    if (parseFloat(cs.opacity) < 1) triggers.push('opacity');
    if (cs.transform !== 'none') triggers.push('transform');
    if (cs.filter !== 'none') triggers.push('filter');
    if (cs.isolation === 'isolate') triggers.push('isolation');
    if (triggers.length) results.push({ el: el.tagName + (el.className ? '.' + el.className : ''), triggers });
    el.children && [...el.children].forEach(check);
  }
  check(root);
  return results;
}

