function buildDropdownCSS() {
  return `
    .dropdown { position: relative; display: inline-block; }
    .dropdown-menu {
      position: absolute;
      top: calc(100% + 4px);
      left: 0;
      min-width: 160px;
      background: white;
      border: 1px solid #e2e8f0;
      border-radius: 8px;
      box-shadow: 0 10px 15px -3px rgba(0,0,0,0.1);
      z-index: 50;
      display: none;
    }
    .dropdown.open .dropdown-menu { display: block; }
  `;
}
function initDropdown(btn) {
  btn.addEventListener('click', () => btn.closest('.dropdown').classList.toggle('open'));
  document.addEventListener('click', e => { if (!e.target.closest('.dropdown')) document.querySelectorAll('.dropdown').forEach(d => d.classList.remove('open')); });
  document.addEventListener('keydown', e => { if (e.key === 'Escape') document.querySelectorAll('.dropdown').forEach(d => d.classList.remove('open')); });
}

function buildImageOverlayCSS() {
