      position: absolute;
      inset: 0;
      background: rgba(0,0,0,0.6);
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      opacity: 0;
      transition: opacity 0.3s;
    }
    .image-card:hover .overlay { opacity: 1; }
    .image-card:hover img { transform: scale(1.05); }
