function buildCalendar(year, month) {
  const date = new Date(year, month, 1);
  const startDay = date.getDay() || 7; // 1=Mon, 7=Sun
  const daysInMonth = new Date(year, month+1, 0).getDate();
  let html = '<div class="calendar">';
  // Header
  ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'].forEach(d => {
    html += `<div class="day-header">${d}</div>`;
  });
  // First day offset
  for (let i = 1; i < startDay; i++) html += '<div class="day empty"></div>';
  // Days
  for (let d = 1; d <= daysInMonth; d++) html += `<div class="day">${d}</div>`;
  html += '</div>';
  return { html, css: '.calendar { display:grid; grid-template-columns:repeat(7,1fr); gap:1px; }' };
}

function initMasonryGrid(grid) {
  const rowHeight = 10;
  const gap = 12;
  function resizeItem(item) {
    const height = item.querySelector('.content').getBoundingClientRect().height;
    item.style.gridRowEnd = `span ${Math.ceil((height + gap) / (rowHeight + gap))}`;
  }
  function resizeAll() { grid.querySelectorAll('.item').forEach(resizeItem); }
  resizeAll();
  window.addEventListener('resize', resizeAll);
}
function buildMasonryCSS() {
  return `
    .masonry-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
      grid-auto-rows: 10px;
