  `;
}

function recommendLayout(description) {
  const gridKeywords = ['grid', '2d', 'columns and rows', 'masonry', 'dashboard', 'magazine', 'calendar'];
  const flexKeywords = ['nav', 'row', 'center', 'inline', 'chat', 'toolbar', 'horizontal', 'vertical list'];
  const lower = description.toLowerCase();
  const gridScore = gridKeywords.filter(k => lower.includes(k)).length;
  const flexScore = flexKeywords.filter(k => lower.includes(k)).length;
  if (gridScore > flexScore) return { choice: 'Grid', reason: 'Two-dimensional layout detected' };
  if (flexScore > gridScore) return { choice: 'Flexbox', reason: 'One-dimensional layout detected' };
  return { choice: 'Either', reason: 'Could work with both — prefer Grid for 2D, Flexbox for 1D' };
}

function buildSubgridCSS() {
